mapper.select:
SELECT sr.*, d.drug_name, u1.real_name as operator_name, u2.real_name as auditor_name FROM sales_return sr LEFT JOIN drug_info d ON sr.drug_id = d.drug_id LEFT JOIN sys_user u1 ON sr.operator_id = u1.user_id LEFT JOIN sys_user u2 ON sr.auditor_id = u2.user_id
AND sr.original_order_id = #{originalOrderId}
AND d.drug_name LIKE CONCAT('%', #{drugName}, '%')
AND sr.status = #{status}
AND sr.create_time >= #{startDate}
AND sr.create_time <= #{endDate}
ORDER BY sr.create_time DESC
